import{_ as a,o as t,c as n,j as r,a as s,a1 as o}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"练火炉","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/6.技艺及称号/能量类/练火炉.md","filePath":"4.资源分区/6.技艺及称号/能量类/练火炉.md"}'),d={name:"4.资源分区/6.技艺及称号/能量类/练火炉.md"};function b(p,e,l,_,i,c){return t(),n("div",null,[...e[0]||(e[0]=[r("h1",{id:"练火炉",tabindex:"-1"},[s("练火炉 "),r("a",{class:"header-anchor",href:"#练火炉","aria-label":'Permalink to "练火炉"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"TMD：绯红庆典040")])])],-1),o('<h1 id="练火炉-1" tabindex="-1">练火炉 <a class="header-anchor" href="#练火炉-1" aria-label="Permalink to &quot;练火炉&quot;">​</a></h1><p>练火炉<br> 技艺<br> 介绍：<br> 这是某一妖祟横行世界最为常见的粗浅术法，汇聚自身阳气致阳关，从而点燃身躯内的火炉以喝退邪祟，习练者大多也只是组织势力从小培养的采矿人或镖师而已。虽说只要肯吃苦，忍的住，掌握一烛境界不过是时间长短而已，不过人阳气有尽，若无补物，过分使用这一术法反而会降低寿命，因此这些修习者也被称为”烛人“。</p><p>练火炉：一烛<br> 有传这是某一高深道法的前身，不过事实如何外人无从知晓。<br> 价格：D+500<br> 前提：<br> 人要想强壮，首先得火力充沛，阳气充足。人身上的“火炉子”在后腰阳关，要把火点起来，就得往里加【阳气】、从而点起命门之火。而提供阳气的就是两边的肾俞，因此修习这一术法要求必须为童男，绝不可与人交媾泄出元精，平时自泄只会让火炉不旺无伤大雅，但一旦破身导致根基损毁，即使是已经有些修为的修习者也会炉破火散，失去【练火炉】全部强化。<br> 效果：<br> 修习者需要打熬身体，勤晒太阳，使体内阳气满溢，从而点燃火炉。人物一旦点起火炉，便获得一种内力变体能量—【阳气】，这是一种至刚至阳的能量，关键属性为耐力+决心。修习到这一境界者精神饱满、阳气充足。但一旦元精外泄，便前功尽弃修为尽毁。<br> 以一个自由动作消耗一点阳气，在本轮的下一次近战攻击中将阳气注入邪祟体内烧灼其身躯，使该次攻击具有【法破】特性并额外具有2点能量加值。</p><p>练火炉：三烛<br> 这以接触到”道“的门槛，也是这一术法的上限。修习者阳气足足是常人的三倍有余，仅有少数天资绝顶或是常年进食补物的修习者才能到达。相传有一修习者夜间被一女鬼采补充，与女鬼夜战二十余回合，不仅自己元精丝毫未泄，反让日的女鬼魂飞魄散。<br> 价格：C+1000<br> 限制：<br> 到这一境界，修习者下腹阳气凝实，在邪祟鬼怪眼中犹如熊熊火炉，一般弱小鬼物见之则避。此时若破身，虽不会修为尽毁失去全部强化，但也失去了再进一步的可能。不过因接下来的修习方法皆掌握在大家宗门手中，难以得到，因此多数修习者也在此止步，娶妻生子，成为富翁家。</p><p>效果：<br> 修习者阳气旺盛，邪祟不侵，修习者免疫B级及以下的疾病来源负面效果。<br> 以一个自由动作消耗6点阳气使其布满体表，持续一轮。本轮中，修习者的能量防御临时提升5点。<br> 当你在进行一次具有【法破】的近战攻击时，如果攻击的目标的生物类型为【灵体】，本次攻击在结算伤害时将等同修习者最多传奇决心点严重伤害转为等量点韧性伤害。</p><hr><p>Copyright ? 2025 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',7)])])}const m=a(d,[["render",b]]);export{f as __pageData,m as default};
